#!/usr/bin/env python3
# -*- coding: utf-8 -*-

import argparse
import csv
import re
import sys
from pathlib import Path

import pandas as pd


def parse_price(val):
    """Convert a messy price string to a plain float."""
    if pd.isna(val):
        return val
    s = str(val).strip()
    if not s:
        return pd.NA
    # Remove currency symbols and spaces
    s = re.sub(r'[\$€£]', '', s)
    s = s.replace(' ', '')
    # Detect European format (comma as decimal separator)
    if ',' in s and '.' in s:
        if s.rfind(',') > s.rfind('.'):
            # European: 1.234,56
            s = s.replace('.', '')
            s = s.replace(',', '.')
        else:
            # US: 1,234.56
            s = s.replace(',', '')
    elif ',' in s and '.' not in s:
        # Could be European without thousands separator: 1234,56
        s = s.replace(',', '.')
    else:
        # US format or plain number
        s = s.replace(',', '')
    try:
        return float(s)
    except ValueError:
        return pd.NA


def normalize_date(val):
    """Convert a messy date string to ISO format YYYY-MM-DD."""
    if pd.isna(val):
        return val
    s = str(val).strip()
    if not s:
        return pd.NA
    try:
        dt = pd.to_datetime(s, dayfirst=False, infer_datetime_format=True, errors='raise')
        return dt.strftime('%Y-%m-%d')
    except Exception:
        return pd.NA


def guess_column_type(series):
    """Return 'date', 'price', or None based on the series content."""
    # Try date
    dates = series.dropna().apply(normalize_date)
    if dates.notna().sum() > len(series) * 0.5:
        return 'date'
    # Try price
    prices = series.dropna().apply(parse_price)
    if prices.notna().sum() > len(series) * 0.5:
        return 'price'
    return None


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('input', type=Path, help='Input CSV file')
    parser.add_argument('-o', '--output', type=Path, default=Path('output.csv'),
                        help='Output CSV file (default: output.csv)')
    args = parser.parse_args()

    # Read CSV with flexible separator (comma or semicolon)
    try:
        df = pd.read_csv(
            args.input,
            sep=r'[;,]',
            engine='python',
            quoting=csv.QUOTE_MINIMAL,
            encoding='utf-8',
            encoding_errors='replace',
            dtype=str,
            keep_default_na=False,
        )
    except Exception as e:
        sys.stderr.write(f'Error reading CSV: {e}\n')
        sys.exit(1)

    # Process each column
    for col in df.columns:
        col_type = guess_column_type(df[col])
        if col_type == 'date':
            df[col] = df[col].apply(normalize_date)
        elif col_type == 'price':
            df[col] = df[col].apply(parse_price)

    # Write output
    df.to_csv(args.output, index=False, quoting=csv.QUOTE_MINIMAL, encoding='utf-8')


if __name__ == '__main__':
    main()
```
